mapper.select:
SELECT *
FROM analytics_audit_log
WHERE user_id = #{userId}
  AND view_id = #{viewId}
ORDER BY period_type ASC, period_label ASC, created_at ASC
LIMIT #{limit}

SELECT *
FROM analytics_audit_log
WHERE user_id = #{userId}
  AND report_key = #{reportKey}

    AND view_id = #{viewId}

ORDER BY created_at DESC
LIMIT #{limit}

SELECT COUNT(*)
FROM analytics_audit_log
WHERE view_id = #{viewId}
  AND period_type = #{periodType}
  AND period_label = #{periodLabel}

SELECT a.*
FROM analytics_audit_log a
LEFT JOIN analytics_llm_insight i ON i.audit_log_id = a.id
WHERE a.user_id = #{userId}
  AND a.report_key = #{reportKey}
  AND a.view_id = #{viewId}
  AND i.id IS NULL
ORDER BY a.created_at DESC
LIMIT #{limit}
